('j01a', 'c01', 'フルスタックエンジニア', 'React/Next.jsとGo言語を用いたWebアプリケーション開発。マイクロサービスアーキテクチャの設計・実装を担当。自社SaaSプロダクトの新機能開発から運用まで幅広く携わっていただきます。', 'FULL_TIME', '東京都渋谷区神南1-2-3', 500, 900, true, 'IT', ARRAY['リモートワーク', 'フレックスタイム'], 'MID_CAREER', NULL, '関東', '10:00〜19:00（フレックス）', ARRAY['健康保険', '通勤交通費全額支給', '退職金'], '実務経験3年以上、React/TypeScript必須', '書類選考 → 技術面接 → 最終面接', 'JR渋谷駅 徒歩5分', '41万円〜75万円', NOW() - INTERVAL '1 day', NOW()),
('j01b', 'c01', '新卒ITエンジニア（27卒）', 'プログラミング未経験OK！入社後3ヶ月の研修でJava/Pythonの基礎から学べます。配属先はWebアプリ開発チームまたはインフラチーム。メンター制度あり。', 'FULL_TIME', '東京都渋谷区神南1-2-3', 300, 400, true, 'IT', ARRAY['未経験歓迎', '新卒歓迎'], 'NEW_GRAD', 2027, '関東', '9:30〜18:30', ARRAY['健康保険', '通勤交通費全額支給', '教育制度', '社員旅行'], '2027年3月卒業見込みの方', '説明会 → ES → 面接2回', 'JR渋谷駅 徒歩5分', '25万円', NOW() - INTERVAL '2 days', NOW()),
('j01c', 'c01', 'AIエンジニア（28卒）', '機械学習・深層学習モデルの研究開発。自社プロダクトへのAI機能実装。Python/PyTorchの知識があれば尚良し。研究職志望の方も歓迎。', 'FULL_TIME', '東京都渋谷区神南1-2-3', 320, 420, true, 'IT', ARRAY['新卒歓迎', 'リモートワーク'], 'NEW_GRAD', 2028, '関東', '10:00〜19:00（フレックス）', ARRAY['健康保険', '通勤交通費全額支給', '教育制度'], '2028年3月卒業見込みの方、理系歓迎', '説明会 → コーディングテスト → 面接2回', 'JR渋谷駅 徒歩5分', '27万円', NOW() - INTERVAL '3 days', NOW()),

